import React from 'react'
import Pitsa from '../../assets/pitsa.png'
import Kuritsa from '../../assets/kuritsa.png'
import './cart.css'
import { Button } from '../../style/Styled'

const Cart = ({openModal}) => {

    const carts = [
        {
            id: 1,
            image: Pitsa,
            title: "Onion Pizza",
            text: "Lorem, ipsum dolor sit amet consectetur adipisicing elit. Repellendus, vel."
        },
        {
            id: 2,
            image: Kuritsa,
            title: "Mix Veg"
        }
    ]

    return (
        <div className='carts'> 
            {carts.map((cart) => (
                <div className='cart' key={cart.id}>
                    <img src={cart.image} alt='boots' width='300'/>
                    <h1>{cart.title}</h1>
                    <Button onClick={ () => openModal(cart)}>Open</Button>
                </div>
            ))}
        </div>
    )
} 

export default Cart
